import psycopg2
import sys

def install_extension(db_name, db_user, db_password, db_host, db_port, extension_name):
    conn = None
    try:
        conn = psycopg2.connect(
            dbname=db_name,
            user=db_user,
            password=db_password,
            host=db_host,
            port=db_port
        )
        conn.autocommit = True
        cur = conn.cursor()

        print(f"Attempting to install extension: {extension_name}...")
        cur.execute(f"CREATE EXTENSION IF NOT EXISTS {extension_name}")
        print(f"Extension '{extension_name}' installed or already exists successfully.")
        cur.close()

    except psycopg2.Error as e:
        print(f"Error installing extension '{extension_name}': {e}")
        # Optionally, check if the error is due to an invalid extension name
        if "unrecognized configuration parameter" in str(e) or "could not open extension control file" in str(e):
            print(f"Note: '{extension_name}' might not be a valid or available extension.")
        elif "must be superuser to create extension" in str(e):
            print("Error: You must have superuser privileges to create extensions.")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if conn:
            conn.close()

if __name__ == "__main__":
    if len(sys.argv) < 7:
        print("Usage: python admin_tool.py <db_name> <db_user> <db_password> <db_host> <db_port> <extension1> [extension2 ...]")
